from .pagination import decode_cursor, encode_cursor

def list_orders(limit=20, cursor=None):
    after = decode_cursor(cursor) if cursor else None
    rows = db.query_orders(after=after, limit=limit + 1)
    nxt = encode_cursor(rows[limit]) if len(rows) > limit else None
    return {'items': rows[:limit], 'next_cursor': nxt}

